      this.rasterSetColor = false;
      this.hasCRS = false;
      this.rasterConvertType = "CONVERT_IMAGE";
      this.thmbUrl = "";
      this.selectedProj = "";
      this.saveFileNm = "";
      this.percentValue = 0;
      this.minLon = 0;
      this.minLat = 0;
      this.maxLon = 0;
      this.maxLat = 0;
      this.bandCnt = 0;
      this.minPx = 0;
